    ClientBuilder AutoEnableCrossSigning(bool @autoEnableCrossSigning);
    /// <summary>
    /// Select a strategy to download room keys from the backup. By default
    /// we download after a decryption failure.
    ///
    /// Take a look at the [`BackupDownloadStrategy`] enum for more options.
    /// </summary>
    ClientBuilder BackupDownloadStrategy(BackupDownloadStrategy @backupDownloadStrategy);
    /// <exception cref="ClientBuildException"></exception>
    Task<Client> Build();
    ClientBuilder CrossProcessLockConfig(CrossProcessLockConfig @crossProcessLockConfig);
    /// <summary>
    /// Set the trust requirement to be used when decrypting events.
    /// </summary>
    ClientBuilder DecryptionSettings(DecryptionSettings @decryptionSettings);
    ClientBuilder DisableAutomaticTokenRefresh();
    /// <summary>
    /// Don't trust any system root certificates, only trust the certificates
    /// provided through
    /// [`add_root_certificates`][ClientBuilder::add_root_certificates].
    /// </summary>
    ClientBuilder DisableBuiltInRootCertificates();
    ClientBuilder DisableSslVerification();
    ClientBuilder DmRoomDefinition(DmRoomDefinition @dmRoomDefinition);
    /// <summary>
    /// Set whether to enable the experimental support for sending and receiving
    /// encrypted room history on invite, per [MSC4268].
    ///
    /// [MSC4268]: https://github.com/matrix-org/matrix-spec-proposals/pull/4268
    /// </summary>
    ClientBuilder EnableShareHistoryOnInvite(bool @enableShareHistoryOnInvite);
    ClientBuilder HomeserverUrl(string @url);
    /// <summary>
    /// Use in-memory session storage.
    /// </summary>
    ClientBuilder InMemoryStore();
    ClientBuilder Proxy(string @url);
    /// <summary>
    /// Add a default request config to this client.
    /// </summary>
    ClientBuilder RequestConfig(RequestConfig @config);
    /// <summary>
    /// Set the strategy to be used for picking recipient devices when sending
    /// an encrypted message.
    /// </summary>
    ClientBuilder RoomKeyRecipientStrategy(CollectStrategy @strategy);
    ClientBuilder ServerName(string @serverName);
    ClientBuilder ServerNameOrHomeserverUrl(string @serverNameOrUrl);
    /// <summary>
    /// Sets the paths that the client will use to store its data and caches
    /// with SQLite.
    ///
    /// Both paths **must** be unique per session as the SDK
    /// stores aren't capable of handling multiple users, however it is
    /// valid to use the same path for both stores on a single session.
    /// </summary>
    ClientBuilder SessionPaths(string @dataPath, string @cachePath);
    ClientBuilder SetSessionDelegate(ClientSessionDelegate @sessionDelegate);
    ClientBuilder SlidingSyncVersionBuilder(SlidingSyncVersionBuilder @versionBuilder);
    /// <summary>
    /// Use SQLite as the session storage.
    /// </summary>
    ClientBuilder SqliteStore(SqliteStoreBuilder @config);
    /// <summary>
    /// Tell the client that the system is memory constrained, like in a push
    /// notification process for example.
    ///
    /// So far, at the time of writing (2025-04-07), it changes the defaults of
    /// `matrix_sdk::SqliteStoreConfig` (if the `sqlite` feature is enabled).
    /// Please check
    /// `matrix_sdk::SqliteStoreConfig::with_low_memory_config`.
    /// </summary>
    ClientBuilder SystemIsMemoryConstrained();
    /// <summary>
    /// Whether the client should support threads client-side or not, and enable
    /// experimental support for MSC4306 (threads subscriptions) or not.
    /// </summary>
    ClientBuilder ThreadsEnabled(bool @enabled, bool @threadSubscriptions);
    ClientBuilder UserAgent(string @userAgent);
    ClientBuilder Username(string @username);
    /// <summary>
    /// Set up the search index store for this client, which is used to store
    /// the message search index locally.
    ///
    /// As soon as this is enabled, messages will start to be indexed, and can
    /// be later queried for search.
    ///
    /// `path` is the directory where the search index will be stored. It must
    /// be unique per session.
    ///
    /// `password` is an optional password to encrypt the search index at rest.
    /// If `None`, the search index will be stored unencrypted.
    /// </summary>
    ClientBuilder WithSearchIndexStore(string @path, string? @password);
