    /// </summary>
    /// <exception cref="NotificationSettingsException"></exception>
    Task<RoomNotificationMode?> GetUserDefinedRoomNotificationMode(string @roomId);
    /// <summary>
    /// Get whether the `.m.rule.call` push rule is enabled
    /// </summary>
    /// <exception cref="NotificationSettingsException"></exception>
