class FfiConverterTypeNotificationSettings: FfiConverter<NotificationSettings, ulong> {
    public static FfiConverterTypeNotificationSettings INSTANCE = new FfiConverterTypeNotificationSettings();


    public override ulong Lower(NotificationSettings value) {
        return value.CallWithPointer(thisPtr => thisPtr);
    }

    public override NotificationSettings Lift(ulong value) {
        return new NotificationSettings(value);
    }

    public override NotificationSettings Read(BigEndianStream stream) {
        return Lift(stream.ReadULong());
    }

    public override int AllocationSize(NotificationSettings value) {
        return 8;
    }

    public override void Write(NotificationSettings value, BigEndianStream stream) {
        stream.WriteULong(Lower(value));
    }
}



/// <summary>
/// Data for the QR code login mechanism.
///
/// The [`QrCodeData`] can be serialized and encoded as a QR code or it can be
/// decoded from a QR code.
/// </summary>
public interface IQrCodeData {
    /// <summary>
    /// The base URL of the homeserver contained within the scanned QR code
    /// data.
    ///
    /// Note: This value is only present when scanning a QR code conforming to
    /// MSC4388.
    /// </summary>
    string? BaseUrl();
    /// <summary>
    /// Get the [`QrCodeIntent`] of this [`QrCodeData`] object.
    ///
    /// This tells us if the creator of the QR code wants to log in or if they
    /// want to log another device in.
    /// </summary>
    QrCodeIntent Intent();
    /// <summary>
    /// The server name contained within the scanned QR code data.
    ///
    /// Note: This value is only present when scanning a QR code that belongs to
    /// a logged in client. The mode where the new client shows the QR code
    /// will return `None`.
    /// </summary>
    string? ServerName();
    /// <summary>
    /// Serialize the [`QrCodeData`] into a byte vector for encoding as a QR
    /// code.
    /// </summary>
    byte[] ToBytes();
}
