/// <summary>
/// Progress of an operation in abstract units.
///
/// Contrary to [`TransmissionProgress`], this allows tracking the progress
/// of sending or receiving a payload in estimated pseudo units representing a
/// percentage. This is helpful in cases where the exact progress in bytes isn't
/// known, for instance, because encryption (which changes the size) happens on
/// the fly.
/// </summary>
/// <param name="Current">
/// How many units were already transferred.
/// </param>
/// <param name="Total">
/// How many units there are in total.
/// </param>
public record AbstractProgress (
    /// <summary>
    /// How many units were already transferred.
    /// </summary>
    ulong Current, 
    /// <summary>
    /// How many units there are in total.
    /// </summary>
    ulong Total
) {
}

class FfiConverterTypeAbstractProgress: FfiConverterRustBuffer<AbstractProgress> {
    public static FfiConverterTypeAbstractProgress INSTANCE = new FfiConverterTypeAbstractProgress();

    public override AbstractProgress Read(BigEndianStream stream) {
        return new AbstractProgress(
            Current: FfiConverterUInt64.INSTANCE.Read(stream),
            Total: FfiConverterUInt64.INSTANCE.Read(stream)
        );
    }

    public override int AllocationSize(AbstractProgress value) {
        return 0
            + FfiConverterUInt64.INSTANCE.AllocationSize(value.Current)
            + FfiConverterUInt64.INSTANCE.AllocationSize(value.Total);
    }

    public override void Write(AbstractProgress value, BigEndianStream stream) {
            FfiConverterUInt64.INSTANCE.Write(value.Current, stream);
            FfiConverterUInt64.INSTANCE.Write(value.Total, stream);
    }
}



