/// <summary>
/// FFI representation of a live location sharing session (MSC3489).
///
/// Corresponds to a `org.matrix.msc3672.beacon_info` state event in the
/// timeline. Location updates are aggregated here as they arrive.
/// </summary>
/// <param name="IsLive">
/// Whether this sharing session is currently active.
/// </param>
/// <param name="Ts">
/// The timestamp when this live location sharing session started
/// (from the `org.matrix.msc3488.ts` field of the originating
/// `beacon_info` state event).
/// 
/// This marks the *beginning* of the session. The session expires at
/// `ts + timeout_ms`.
/// </param>
/// <param name="Description">
/// An optional human-readable label for this sharing session.
/// </param>
/// <param name="TimeoutMs">
/// Duration of the session in milliseconds.
/// </param>
/// <param name="AssetType">
/// The asset type of the beacon (e.g. `Sender` for the user's own
/// location, `Pin` for a fixed point of interest).
/// </param>
/// <param name="Locations">
/// All location updates received so far, sorted oldest-first.
/// </param>
public record LiveLocationContent (
    /// <summary>
    /// Whether this sharing session is currently active.
    /// </summary>
    bool IsLive, 
    /// <summary>
    /// The timestamp when this live location sharing session started
    /// (from the `org.matrix.msc3488.ts` field of the originating
    /// `beacon_info` state event).
    ///
    /// This marks the *beginning* of the session. The session expires at
    /// `ts + timeout_ms`.
    /// </summary>
    Timestamp Ts, 
    /// <summary>
    /// An optional human-readable label for this sharing session.
    /// </summary>
    string? Description, 
    /// <summary>
    /// Duration of the session in milliseconds.
    /// </summary>
    ulong TimeoutMs, 
    /// <summary>
    /// The asset type of the beacon (e.g. `Sender` for the user's own
    /// location, `Pin` for a fixed point of interest).
    /// </summary>
    AssetType AssetType, 
    /// <summary>
    /// All location updates received so far, sorted oldest-first.
    /// </summary>
    BeaconInfo[] Locations
) {
}

class FfiConverterTypeLiveLocationContent: FfiConverterRustBuffer<LiveLocationContent> {
    public static FfiConverterTypeLiveLocationContent INSTANCE = new FfiConverterTypeLiveLocationContent();

    public override LiveLocationContent Read(BigEndianStream stream) {
        return new LiveLocationContent(
            IsLive: FfiConverterBoolean.INSTANCE.Read(stream),
            Ts: FfiConverterTypeTimestamp.INSTANCE.Read(stream),
            Description: FfiConverterOptionalString.INSTANCE.Read(stream),
            TimeoutMs: FfiConverterUInt64.INSTANCE.Read(stream),
            AssetType: FfiConverterTypeAssetType.INSTANCE.Read(stream),
            Locations: FfiConverterSequenceTypeBeaconInfo.INSTANCE.Read(stream)
        );
    }

    public override int AllocationSize(LiveLocationContent value) {
        return 0
            + FfiConverterBoolean.INSTANCE.AllocationSize(value.IsLive)
            + FfiConverterTypeTimestamp.INSTANCE.AllocationSize(value.Ts)
            + FfiConverterOptionalString.INSTANCE.AllocationSize(value.Description)
            + FfiConverterUInt64.INSTANCE.AllocationSize(value.TimeoutMs)
            + FfiConverterTypeAssetType.INSTANCE.AllocationSize(value.AssetType)
            + FfiConverterSequenceTypeBeaconInfo.INSTANCE.AllocationSize(value.Locations);
    }

    public override void Write(LiveLocationContent value, BigEndianStream stream) {
            FfiConverterBoolean.INSTANCE.Write(value.IsLive, stream);
            FfiConverterTypeTimestamp.INSTANCE.Write(value.Ts, stream);
            FfiConverterOptionalString.INSTANCE.Write(value.Description, stream);
            FfiConverterUInt64.INSTANCE.Write(value.TimeoutMs, stream);
            FfiConverterTypeAssetType.INSTANCE.Write(value.AssetType, stream);
            FfiConverterSequenceTypeBeaconInfo.INSTANCE.Write(value.Locations, stream);
    }
}



