) : IDisposable {
    public void Dispose() {
    FFIObjectUtil.DisposeAll(
            this.Event,
            this.RawEvent,
            this.SenderInfo,
            this.RoomInfo,
            this.IsNoisy,
            this.HasMention,
            this.ThreadId,
            this.Actions);
    }
}

