/// <summary>
/// A passphrase from which a key is to be derived.
/// </summary>
/// <param name="Algorithm">
/// The algorithm to use to generate the key from the passphrase.
/// 
/// Must be `m.pbkdf2`.
/// </param>
/// <param name="Salt">
/// The salt used in PBKDF2.
/// </param>
/// <param name="Iterations">
/// The number of iterations to use in PBKDF2.
/// </param>
/// <param name="Bits">
/// The number of bits to generate for the key.
/// 
/// Defaults to 256
/// </param>
public record PassPhrase (
    /// <summary>
    /// The algorithm to use to generate the key from the passphrase.
    ///
    /// Must be `m.pbkdf2`.
    /// </summary>
    KeyDerivationAlgorithm Algorithm, 
    /// <summary>
    /// The salt used in PBKDF2.
    /// </summary>
    string Salt, 
    /// <summary>
    /// The number of iterations to use in PBKDF2.
    /// </summary>
    ulong Iterations, 
    /// <summary>
    /// The number of bits to generate for the key.
    ///
    /// Defaults to 256
    /// </summary>
    ulong Bits
) {
}

class FfiConverterTypePassPhrase: FfiConverterRustBuffer<PassPhrase> {
    public static FfiConverterTypePassPhrase INSTANCE = new FfiConverterTypePassPhrase();

    public override PassPhrase Read(BigEndianStream stream) {
        return new PassPhrase(
            Algorithm: FfiConverterTypeKeyDerivationAlgorithm.INSTANCE.Read(stream),
            Salt: FfiConverterString.INSTANCE.Read(stream),
            Iterations: FfiConverterUInt64.INSTANCE.Read(stream),
            Bits: FfiConverterUInt64.INSTANCE.Read(stream)
        );
    }

    public override int AllocationSize(PassPhrase value) {
        return 0
            + FfiConverterTypeKeyDerivationAlgorithm.INSTANCE.AllocationSize(value.Algorithm)
            + FfiConverterString.INSTANCE.AllocationSize(value.Salt)
            + FfiConverterUInt64.INSTANCE.AllocationSize(value.Iterations)
            + FfiConverterUInt64.INSTANCE.AllocationSize(value.Bits);
    }

    public override void Write(PassPhrase value, BigEndianStream stream) {
            FfiConverterTypeKeyDerivationAlgorithm.INSTANCE.Write(value.Algorithm, stream);
            FfiConverterString.INSTANCE.Write(value.Salt, stream);
            FfiConverterUInt64.INSTANCE.Write(value.Iterations, stream);
            FfiConverterUInt64.INSTANCE.Write(value.Bits, stream);
    }
}



