/// <param name="DisplayName">
/// The room's name from the room state event if received from sync, or one
/// that's been computed otherwise.
/// </param>
/// <param name="RawName">
/// Room name as defined by the room state event only.
/// </param>
/// <param name="IsPublic">
/// Whether the room is public or not, based on the join rules.
/// 
/// Can be `None` if the join rules state event is not available for this
/// room.
/// </param>
/// <param name="SuccessorRoom">
/// If present, it means the room has been archived/upgraded.
/// </param>
/// <param name="Inviter">
/// Member who invited the current user to a room that's in the invited
/// state.
/// 
/// Can be missing if the room membership invite event is missing from the
/// store.
/// </param>
/// <param name="IsMarkedUnread">
/// Whether this room has been explicitly marked as unread
/// </param>
/// <param name="NumUnreadMessages">
/// "Interesting" messages received in that room, independently of the
/// notification settings.
/// </param>
/// <param name="NumUnreadNotifications">
/// Events that will notify the user, according to their
/// notification settings.
/// </param>
/// <param name="NumUnreadMentions">
/// Events causing mentions/highlights for the user, according to their
/// notification settings.
/// </param>
/// <param name="FullyReadEventId">
/// Event ID of the user's `m.fully_read` marker for this room, if any.
/// </param>
/// <param name="PinnedEventIds">
/// The currently pinned event ids.
/// </param>
/// <param name="JoinRule">
/// The join rule for this room, if known.
/// </param>
/// <param name="HistoryVisibility">
/// The history visibility for this room, if known.
/// </param>
/// <param name="PowerLevels">
/// This room's current power levels.
/// 
/// Can be missing if the room power levels event is missing from the store.
/// </param>
/// <param name="RoomVersion">
/// This room's version.
/// </param>
/// <param name="PrivilegedCreatorsRole">
/// Whether creators are privileged over every other user (have infinite
/// power level).
/// </param>
public record RoomInfo (
    string Id, 
    EncryptionState EncryptionState, 
    string[]? Creators, 
    /// <summary>
    /// The room's name from the room state event if received from sync, or one
    /// that's been computed otherwise.
    /// </summary>
    string? DisplayName, 
    /// <summary>
    /// Room name as defined by the room state event only.
    /// </summary>
    string? RawName, 
    string? Topic, 
    string? AvatarUrl, 
    bool IsDirect, 
    bool IsDm, 
    /// <summary>
    /// Whether the room is public or not, based on the join rules.
    ///
    /// Can be `None` if the join rules state event is not available for this
    /// room.
    /// </summary>
    bool? IsPublic, 
    bool IsSpace, 
    /// <summary>
    /// If present, it means the room has been archived/upgraded.
    /// </summary>
    SuccessorRoom? SuccessorRoom, 
    bool IsFavourite, 
    bool IsLowPriority, 
    string? CanonicalAlias, 
    string[] AlternativeAliases, 
    Membership Membership, 
    /// <summary>
    /// Member who invited the current user to a room that's in the invited
    /// state.
    ///
    /// Can be missing if the room membership invite event is missing from the
    /// store.
    /// </summary>
    RoomMember? Inviter, 
    RoomHero[] Heroes, 
    ulong ActiveMembersCount, 
    ulong InvitedMembersCount, 
    ulong JoinedMembersCount, 
    ulong ActiveServiceMembersCount, 
    string[] ServiceMembers, 
    ulong HighlightCount, 
    ulong NotificationCount, 
    RoomNotificationMode? CachedUserDefinedNotificationMode, 
    bool HasRoomCall, 
    string[] ActiveRoomCallParticipants, 
    RtcCallIntentConsensus ActiveRoomCallConsensusIntent, 
    /// <summary>
    /// Whether this room has been explicitly marked as unread
    /// </summary>
    bool IsMarkedUnread, 
    /// <summary>
    /// "Interesting" messages received in that room, independently of the
    /// notification settings.
    /// </summary>
    ulong NumUnreadMessages, 
    /// <summary>
    /// Events that will notify the user, according to their
    /// notification settings.
    /// </summary>
    ulong NumUnreadNotifications, 
    /// <summary>
    /// Events causing mentions/highlights for the user, according to their
    /// notification settings.
    /// </summary>
    ulong NumUnreadMentions, 
    /// <summary>
    /// Event ID of the user's `m.fully_read` marker for this room, if any.
    /// </summary>
    string? FullyReadEventId, 
    /// <summary>
    /// The currently pinned event ids.
    /// </summary>
    string[] PinnedEventIds, 
    /// <summary>
    /// The join rule for this room, if known.
    /// </summary>
    JoinRule? JoinRule, 
    /// <summary>
    /// The history visibility for this room, if known.
    /// </summary>
    RoomHistoryVisibility HistoryVisibility, 
    /// <summary>
    /// This room's current power levels.
    ///
    /// Can be missing if the room power levels event is missing from the store.
    /// </summary>
    RoomPowerLevels? PowerLevels, 
    /// <summary>
    /// This room's version.
    /// </summary>
    string? RoomVersion, 
    /// <summary>
    /// Whether creators are privileged over every other user (have infinite
    /// power level).
    /// </summary>
    bool PrivilegedCreatorsRole
) : IDisposable {
    public void Dispose() {
    FFIObjectUtil.DisposeAll(
            this.Id,
            this.EncryptionState,
            this.Creators,
            this.DisplayName,
            this.RawName,
            this.Topic,
            this.AvatarUrl,
            this.IsDirect,
            this.IsDm,
            this.IsPublic,
            this.IsSpace,
            this.SuccessorRoom,
            this.IsFavourite,
            this.IsLowPriority,
            this.CanonicalAlias,
            this.AlternativeAliases,
            this.Membership,
            this.Inviter,
            this.Heroes,
            this.ActiveMembersCount,
            this.InvitedMembersCount,
            this.JoinedMembersCount,
            this.ActiveServiceMembersCount,
            this.ServiceMembers,
            this.HighlightCount,
            this.NotificationCount,
            this.CachedUserDefinedNotificationMode,
            this.HasRoomCall,
            this.ActiveRoomCallParticipants,
            this.ActiveRoomCallConsensusIntent,
            this.IsMarkedUnread,
            this.NumUnreadMessages,
            this.NumUnreadNotifications,
            this.NumUnreadMentions,
            this.FullyReadEventId,
            this.PinnedEventIds,
            this.JoinRule,
            this.HistoryVisibility,
            this.PowerLevels,
            this.RoomVersion,
            this.PrivilegedCreatorsRole);
    }
}

