/// <summary>
/// A push ruleset scopes a set of rules according to some criteria.
/// </summary>
/// <param name="Content">
/// These rules configure behavior for (unencrypted) messages that match
/// certain patterns.
/// </param>
/// <param name="Override">
/// These user-configured rules are given the highest priority.
/// 
/// This field is named `override_` instead of `override` because the latter
/// is a reserved keyword in Rust.
/// </param>
/// <param name="Room">
/// These rules change the behavior of all messages for a given room.
/// </param>
/// <param name="Sender">
/// These rules configure notification behavior for messages from a specific
/// Matrix user ID.
/// </param>
/// <param name="Underride">
/// These rules are identical to override rules, but have a lower priority
/// than `content`, `room` and `sender` rules.
/// </param>
public record Ruleset (
    /// <summary>
    /// These rules configure behavior for (unencrypted) messages that match
    /// certain patterns.
    /// </summary>
    PatternedPushRule[] Content, 
    /// <summary>
    /// These user-configured rules are given the highest priority.
    ///
    /// This field is named `override_` instead of `override` because the latter
    /// is a reserved keyword in Rust.
    /// </summary>
    ConditionalPushRule[] Override, 
    /// <summary>
    /// These rules change the behavior of all messages for a given room.
    /// </summary>
    SimplePushRule[] Room, 
    /// <summary>
    /// These rules configure notification behavior for messages from a specific
    /// Matrix user ID.
    /// </summary>
    SimplePushRule[] Sender, 
    /// <summary>
    /// These rules are identical to override rules, but have a lower priority
    /// than `content`, `room` and `sender` rules.
    /// </summary>
    ConditionalPushRule[] Underride
) {
}

class FfiConverterTypeRuleset: FfiConverterRustBuffer<Ruleset> {
    public static FfiConverterTypeRuleset INSTANCE = new FfiConverterTypeRuleset();

    public override Ruleset Read(BigEndianStream stream) {
        return new Ruleset(
            Content: FfiConverterSequenceTypePatternedPushRule.INSTANCE.Read(stream),
            Override: FfiConverterSequenceTypeConditionalPushRule.INSTANCE.Read(stream),
            Room: FfiConverterSequenceTypeSimplePushRule.INSTANCE.Read(stream),
            Sender: FfiConverterSequenceTypeSimplePushRule.INSTANCE.Read(stream),
            Underride: FfiConverterSequenceTypeConditionalPushRule.INSTANCE.Read(stream)
        );
    }

    public override int AllocationSize(Ruleset value) {
        return 0
            + FfiConverterSequenceTypePatternedPushRule.INSTANCE.AllocationSize(value.Content)
            + FfiConverterSequenceTypeConditionalPushRule.INSTANCE.AllocationSize(value.Override)
            + FfiConverterSequenceTypeSimplePushRule.INSTANCE.AllocationSize(value.Room)
            + FfiConverterSequenceTypeSimplePushRule.INSTANCE.AllocationSize(value.Sender)
            + FfiConverterSequenceTypeConditionalPushRule.INSTANCE.AllocationSize(value.Underride);
    }

    public override void Write(Ruleset value, BigEndianStream stream) {
            FfiConverterSequenceTypePatternedPushRule.INSTANCE.Write(value.Content, stream);
            FfiConverterSequenceTypeConditionalPushRule.INSTANCE.Write(value.Override, stream);
            FfiConverterSequenceTypeSimplePushRule.INSTANCE.Write(value.Room, stream);
            FfiConverterSequenceTypeSimplePushRule.INSTANCE.Write(value.Sender, stream);
            FfiConverterSequenceTypeConditionalPushRule.INSTANCE.Write(value.Underride, stream);
    }
}



