/// <summary>
/// Structure representing a room in a space and aggregated information
/// relevant to the UI layer.
/// </summary>
/// <param name="RoomId">
/// The ID of the room.
/// </param>
/// <param name="CanonicalAlias">
/// The canonical alias of the room, if any.
/// </param>
/// <param name="DisplayName">
/// The room's name from the room state event if received from sync, or one
/// that's been computed otherwise.
/// </param>
/// <param name="RawName">
/// Room name as defined by the room state event only.
/// </param>
/// <param name="Topic">
/// The topic of the room, if any.
/// </param>
/// <param name="AvatarUrl">
/// The URL for the room's avatar, if one is set.
/// </param>
/// <param name="RoomType">
/// The type of room from `m.room.create`, if any.
/// </param>
/// <param name="NumJoinedMembers">
/// The number of members joined to the room.
/// </param>
/// <param name="JoinRule">
/// The join rule of the room.
/// </param>
/// <param name="WorldReadable">
/// Whether the room may be viewed by users without joining.
/// </param>
/// <param name="GuestCanJoin">
/// Whether guest users may join the room and participate in it.
/// </param>
/// <param name="IsDirect">
/// Whether this room is a direct room.
/// 
/// Only set if the room is known to the client otherwise we
/// assume DMs shouldn't be exposed publicly in spaces.
/// </param>
/// <param name="ChildrenCount">
/// The number of children room this has, if a space.
/// </param>
/// <param name="State">
/// Whether this room is joined, left etc.
/// </param>
/// <param name="Heroes">
/// A list of room members considered to be heroes.
/// </param>
/// <param name="Via">
/// The via parameters of the room.
/// </param>
/// <param name="IsDm">
/// Whether this room is a DM, if known.
/// Note this value can be calculated following some assumptions and is not
/// guaranteed to be accurate.
/// </param>
public record SpaceRoom (
    /// <summary>
    /// The ID of the room.
    /// </summary>
    string RoomId, 
    /// <summary>
    /// The canonical alias of the room, if any.
    /// </summary>
    string? CanonicalAlias, 
    /// <summary>
    /// The room's name from the room state event if received from sync, or one
    /// that's been computed otherwise.
    /// </summary>
    string DisplayName, 
    /// <summary>
    /// Room name as defined by the room state event only.
    /// </summary>
    string? RawName, 
    /// <summary>
    /// The topic of the room, if any.
    /// </summary>
    string? Topic, 
    /// <summary>
    /// The URL for the room's avatar, if one is set.
    /// </summary>
    string? AvatarUrl, 
    /// <summary>
    /// The type of room from `m.room.create`, if any.
    /// </summary>
    RoomType RoomType, 
    /// <summary>
    /// The number of members joined to the room.
    /// </summary>
    ulong NumJoinedMembers, 
    /// <summary>
    /// The join rule of the room.
    /// </summary>
    JoinRule? JoinRule, 
    /// <summary>
    /// Whether the room may be viewed by users without joining.
    /// </summary>
    bool? WorldReadable, 
    /// <summary>
    /// Whether guest users may join the room and participate in it.
    /// </summary>
    bool GuestCanJoin, 
    /// <summary>
    /// Whether this room is a direct room.
    ///
    /// Only set if the room is known to the client otherwise we
    /// assume DMs shouldn't be exposed publicly in spaces.
    /// </summary>
    bool? IsDirect, 
    /// <summary>
    /// The number of children room this has, if a space.
    /// </summary>
    ulong ChildrenCount, 
    /// <summary>
    /// Whether this room is joined, left etc.
    /// </summary>
    Membership? State, 
    /// <summary>
    /// A list of room members considered to be heroes.
    /// </summary>
    RoomHero[]? Heroes, 
    /// <summary>
    /// The via parameters of the room.
    /// </summary>
    string[] Via, 
    /// <summary>
    /// Whether this room is a DM, if known.
    /// Note this value can be calculated following some assumptions and is not
    /// guaranteed to be accurate.
    /// </summary>
    bool? IsDm
) {
