/// <summary>
/// Each `ThreadListItem` represents one thread root event in the room. The
/// fields are pre-resolved from the raw homeserver response: the sender's
/// profile is fetched eagerly and the event content is parsed into a
/// `TimelineItemContent` so that consumers can render the item without any
/// additional work.
///
/// `ThreadListItem`s are produced page by page via `Room::load_thread_list()`
/// and are accumulated inside the `ThreadListService` as pages are fetched
/// through `ThreadListService::paginate()`.
/// </summary>
/// <param name="RootEvent">
/// The thread root event.
/// 
/// Contains the event ID, timestamp, sender, sender profile, and parsed
/// content of the thread's root message. Use `root_event.event_id` to open
/// a per-thread `Timeline` or to navigate the user to the thread view.
/// </param>
/// <param name="LatestEvent">
/// The latest event in the thread (i.e. the most recent reply), if
/// available.
/// 
/// Initially populated from the server's bundled thread summary and
/// updated in real time as new events arrive via sync or back-pagination.
/// </param>
/// <param name="NumReplies">
/// The number of replies in this thread (excluding the root event).
/// 
/// Initially populated from the server's bundled thread summary and
/// updated in real time as new events arrive via sync.
/// </param>
public record ThreadListItem (
    /// <summary>
    /// The thread root event.
    ///
    /// Contains the event ID, timestamp, sender, sender profile, and parsed
    /// content of the thread's root message. Use `root_event.event_id` to open
    /// a per-thread `Timeline` or to navigate the user to the thread view.
    /// </summary>
    ThreadListItemEvent RootEvent, 
    /// <summary>
    /// The latest event in the thread (i.e. the most recent reply), if
    /// available.
    ///
    /// Initially populated from the server's bundled thread summary and
    /// updated in real time as new events arrive via sync or back-pagination.
    /// </summary>
    ThreadListItemEvent? LatestEvent, 
    /// <summary>
    /// The number of replies in this thread (excluding the root event).
    ///
    /// Initially populated from the server's bundled thread summary and
    /// updated in real time as new events arrive via sync.
    /// </summary>
    uint NumReplies
) : IDisposable {
    public void Dispose() {
    FFIObjectUtil.DisposeAll(
            this.RootEvent,
            this.LatestEvent,
            this.NumReplies);
    }
}

class FfiConverterTypeThreadListItem: FfiConverterRustBuffer<ThreadListItem> {
    public static FfiConverterTypeThreadListItem INSTANCE = new FfiConverterTypeThreadListItem();

    public override ThreadListItem Read(BigEndianStream stream) {
        return new ThreadListItem(
            RootEvent: FfiConverterTypeThreadListItemEvent.INSTANCE.Read(stream),
            LatestEvent: FfiConverterOptionalTypeThreadListItemEvent.INSTANCE.Read(stream),
            NumReplies: FfiConverterUInt32.INSTANCE.Read(stream)
        );
    }

    public override int AllocationSize(ThreadListItem value) {
        return 0
            + FfiConverterTypeThreadListItemEvent.INSTANCE.AllocationSize(value.RootEvent)
            + FfiConverterOptionalTypeThreadListItemEvent.INSTANCE.AllocationSize(value.LatestEvent)
            + FfiConverterUInt32.INSTANCE.AllocationSize(value.NumReplies);
    }

    public override void Write(ThreadListItem value, BigEndianStream stream) {
            FfiConverterTypeThreadListItemEvent.INSTANCE.Write(value.RootEvent, stream);
            FfiConverterOptionalTypeThreadListItemEvent.INSTANCE.Write(value.LatestEvent, stream);
            FfiConverterUInt32.INSTANCE.Write(value.NumReplies, stream);
    }
}



