    TimelineFilter Filter, 
    /// <summary>
    /// An optional String that will be prepended to
    /// all the timeline item's public IDs, making it possible to
    /// distinguish different timeline instances from each other.
    /// </summary>
    string? publicIdPrefix, 
    /// <summary>
    /// How often to insert date dividers
    /// </summary>
    DateDividerMode DateDividerMode, 
    /// <summary>
    /// Should the read receipts and read markers be tracked for the timeline
    /// items in this instance and on which event types?
    ///
    /// As this has a non negligible performance impact, make sure to enable it
    /// only when you need it.
    /// </summary>
    TimelineReadReceiptTracking TrackReadReceipts, 
    /// <summary>
    /// Whether this timeline instance should report UTDs through the client's
    /// delegate.
    /// </summary>
    bool ReportUtds
) : IDisposable {
    public void Dispose() {
    FFIObjectUtil.DisposeAll(
            this.Focus,
            this.Filter,
            this.publicIdPrefix,
            this.DateDividerMode,
            this.TrackReadReceipts,
            this.ReportUtds);
