/// <summary>
/// Configuration to save logs to (rotated) log-files.
/// </summary>
/// <param name="Path">
/// Base location for all the log files.
/// </param>
/// <param name="FilePrefix">
/// Prefix for the log files' names.
/// </param>
/// <param name="FileSuffix">
/// Optional suffix for the log file's names.
/// 
/// Default is ".log" if not specified.
/// </param>
/// <param name="MaxTotalSizeBytes">
/// Maximum total size of all log files combined in bytes.
/// 
/// When the total size of all log files with the configured prefix and
/// suffix exceeds this limit, the oldest files will be removed until
/// the total is below the limit.
/// 
/// This is useful to prevent log files from consuming too much disk space
/// over time, even with multiple rotated files.
/// 
/// Default: 10MB (10 * 1024 * 1024 bytes) if not specified.
/// </param>
/// <param name="MaxAgeSeconds">
/// Maximum age of log files in seconds.
/// 
/// Log files older than this age will be automatically removed during
/// cleanup. This is checked when the writer is created and during
/// rotation operations.
/// 
/// Default: 1 week (7 * 24 * 60 * 60 seconds) if not specified.
/// </param>
public record TracingFileConfiguration (
    /// <summary>
    /// Base location for all the log files.
    /// </summary>
    string Path, 
    /// <summary>
    /// Prefix for the log files' names.
    /// </summary>
    string FilePrefix, 
    /// <summary>
    /// Optional suffix for the log file's names.
    ///
    /// Default is ".log" if not specified.
    /// </summary>
    string? FileSuffix, 
    /// <summary>
    /// Maximum total size of all log files combined in bytes.
    ///
    /// When the total size of all log files with the configured prefix and
    /// suffix exceeds this limit, the oldest files will be removed until
    /// the total is below the limit.
    ///
    /// This is useful to prevent log files from consuming too much disk space
    /// over time, even with multiple rotated files.
    ///
    /// Default: 10MB (10 * 1024 * 1024 bytes) if not specified.
    /// </summary>
    ulong? MaxTotalSizeBytes, 
    /// <summary>
    /// Maximum age of log files in seconds.
    ///
    /// Log files older than this age will be automatically removed during
    /// cleanup. This is checked when the writer is created and during
    /// rotation operations.
    ///
    /// Default: 1 week (7 * 24 * 60 * 60 seconds) if not specified.
    /// </summary>
    ulong? MaxAgeSeconds
) {
}

class FfiConverterTypeTracingFileConfiguration: FfiConverterRustBuffer<TracingFileConfiguration> {
    public static FfiConverterTypeTracingFileConfiguration INSTANCE = new FfiConverterTypeTracingFileConfiguration();

    public override TracingFileConfiguration Read(BigEndianStream stream) {
        return new TracingFileConfiguration(
            Path: FfiConverterString.INSTANCE.Read(stream),
            FilePrefix: FfiConverterString.INSTANCE.Read(stream),
            FileSuffix: FfiConverterOptionalString.INSTANCE.Read(stream),
            MaxTotalSizeBytes: FfiConverterOptionalUInt64.INSTANCE.Read(stream),
            MaxAgeSeconds: FfiConverterOptionalUInt64.INSTANCE.Read(stream)
        );
    }

    public override int AllocationSize(TracingFileConfiguration value) {
        return 0
            + FfiConverterString.INSTANCE.AllocationSize(value.Path)
            + FfiConverterString.INSTANCE.AllocationSize(value.FilePrefix)
            + FfiConverterOptionalString.INSTANCE.AllocationSize(value.FileSuffix)
            + FfiConverterOptionalUInt64.INSTANCE.AllocationSize(value.MaxTotalSizeBytes)
            + FfiConverterOptionalUInt64.INSTANCE.AllocationSize(value.MaxAgeSeconds);
    }

    public override void Write(TracingFileConfiguration value, BigEndianStream stream) {
            FfiConverterString.INSTANCE.Write(value.Path, stream);
            FfiConverterString.INSTANCE.Write(value.FilePrefix, stream);
            FfiConverterOptionalString.INSTANCE.Write(value.FileSuffix, stream);
            FfiConverterOptionalUInt64.INSTANCE.Write(value.MaxTotalSizeBytes, stream);
            FfiConverterOptionalUInt64.INSTANCE.Write(value.MaxAgeSeconds, stream);
    }
}



