            case BackupUploadState.Uploading variant_value:
                return 4
                    + FfiConverterUInt32.INSTANCE.AllocationSize(variant_value.BackedUpCount)
                    + FfiConverterUInt32.INSTANCE.AllocationSize(variant_value.TotalCount);
            case BackupUploadState.Error variant_value:
                return 4;
            case BackupUploadState.Done variant_value:
                return 4;
            default:
                throw new publicException(String.Format("invalid enum value '{0}' in FfiConverterTypeBackupUploadState.AllocationSize()", value));
        }
    }

    public override void Write(BackupUploadState value, BigEndianStream stream) {
        switch (value) {
            case BackupUploadState.Waiting variant_value:
                stream.WriteInt(1);
                break;
            case BackupUploadState.Uploading variant_value:
                stream.WriteInt(2);
                FfiConverterUInt32.INSTANCE.Write(variant_value.BackedUpCount, stream);
                FfiConverterUInt32.INSTANCE.Write(variant_value.TotalCount, stream);
                break;
            case BackupUploadState.Error variant_value:
                stream.WriteInt(3);
                break;
            case BackupUploadState.Done variant_value:
                stream.WriteInt(4);
                break;
            default:
                throw new publicException(String.Format("invalid enum value '{0}' in FfiConverterTypeBackupUploadState.Write()", value));
        }
    }
}







public record BatchNotificationResult: IDisposable  {
    
    /// <summary>
    /// We have more detailed information about the notification.
    /// </summary>
    public record Ok (
        NotificationStatus Status
    ) : BatchNotificationResult {}
    
    /// <summary>
    /// An error occurred while trying to fetch the notification.
    /// </summary>
    public record Error (
        string Message
    ) : BatchNotificationResult {}
    

    
    public void Dispose() {
        switch (this) {
            case BatchNotificationResult.Ok variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.Status);
                break;
            case BatchNotificationResult.Error variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.Message);
                break;
            default:
                throw new publicException(String.Format("invalid enum value '{0}' in BatchNotificationResult.Dispose()", this));
        }
    }
    
}

