/// <summary>
/// Error type describing failures that can happen while exporting a
/// [`SecretsBundle`] from a SQLite store.
/// </summary>
public class BundleExportException: UniffiException {
    BundleExportException() : base() {}
    BundleExportException(String @Message) : base(@Message) {}

    // Each variant is a nested class
    
    /// <summary>
    /// The SQLite store couldn't be opened.
    /// </summary>
    
    public class OpenStoreException : BundleExportException {
        // Members
        public string @msg;

        // Constructor
        public OpenStoreException(
                string @msg) : base(
                "@msg" + "=" + @msg) {

            this.@msg = @msg;
        }
    }
    
    /// <summary>
    /// Data from the SQLite store couldn't be exported.
    /// </summary>
    
    public class StoreException : BundleExportException {
        // Members
        public string @msg;

        // Constructor
        public StoreException(
                string @msg) : base(
                "@msg" + "=" + @msg) {

            this.@msg = @msg;
        }
    }
    
    /// <summary>
    /// The store doesn't contain a secrets bundle or it couldn't be read from
    /// the store.
    /// </summary>
    
    public class SecretException : BundleExportException {
        // Members
        public string @msg;

        // Constructor
        public SecretException(
                string @msg) : base(
                "@msg" + "=" + @msg) {

            this.@msg = @msg;
        }
    }
    
    /// <summary>
    /// The store is empty and doesn't contain a secrets bundle.
    /// </summary>
    public class StoreEmpty : BundleExportException {
        public StoreEmpty() : base() {}
    }
    
    
    /// <summary>
    /// A JSON object couldn't be deserialized while the secrets bundle was
    /// exported.
    /// </summary>
    
    public class Json : BundleExportException {
        // Members
        public string @msg;

        // Constructor
        public Json(
                string @msg) : base(
                "@msg" + "=" + @msg) {

            this.@msg = @msg;
        }
    }
    
    /// <summary>
    /// Error returned when the secrets bundle is missing a backup key or
    /// includes one that doesn’t match the key configured for the active backup
    /// version.
    /// </summary>
    public class InvalidBackup : BundleExportException {
        public InvalidBackup() : base() {}
    }
    
    

    
}

class FfiConverterTypeBundleExportError : FfiConverterRustBuffer<BundleExportException>, CallStatusErrorHandler<BundleExportException> {
    public static FfiConverterTypeBundleExportError INSTANCE = new FfiConverterTypeBundleExportError();

    public override BundleExportException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new BundleExportException.OpenStoreException(
                    FfiConverterString.INSTANCE.Read(stream));
            case 2:
                return new BundleExportException.StoreException(
                    FfiConverterString.INSTANCE.Read(stream));
            case 3:
                return new BundleExportException.SecretException(
                    FfiConverterString.INSTANCE.Read(stream));
            case 4:
                return new BundleExportException.StoreEmpty();
            case 5:
                return new BundleExportException.Json(
                    FfiConverterString.INSTANCE.Read(stream));
            case 6:
                return new BundleExportException.InvalidBackup();
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeBundleExportError.Read()", value));
        }
    }

    public override int AllocationSize(BundleExportException value) {
        switch (value) {

            case BundleExportException.OpenStoreException variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case BundleExportException.StoreException variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case BundleExportException.SecretException variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case BundleExportException.StoreEmpty variant_value:
                return 4;

            case BundleExportException.Json variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case BundleExportException.InvalidBackup variant_value:
                return 4;
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeBundleExportError.AllocationSize()", value));
        }
    }

    public override void Write(BundleExportException value, BigEndianStream stream) {
        switch (value) {
            case BundleExportException.OpenStoreException variant_value:
                stream.WriteInt(1);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case BundleExportException.StoreException variant_value:
                stream.WriteInt(2);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case BundleExportException.SecretException variant_value:
                stream.WriteInt(3);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case BundleExportException.StoreEmpty variant_value:
                stream.WriteInt(4);
                break;
            case BundleExportException.Json variant_value:
                stream.WriteInt(5);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case BundleExportException.InvalidBackup variant_value:
                stream.WriteInt(6);
                break;
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeBundleExportError.Write()", value));
        }
    }
}





