public class ClientException: UniffiException {
    ClientException() : base() {}
    ClientException(String @Message) : base(@Message) {}

    // Each variant is a nested class
    
    
    public class Generic : ClientException {
        // Members
        public string @msg;
        public string? @details;

        // Constructor
        public Generic(
                string @msg, 
                string? @details) : base(
                "@msg" + "=" + @msg+ ", " +
                "@details" + "=" + @details) {

            this.@msg = @msg;

            this.@details = @details;
        }
    }
    
    
    public class MatrixApi : ClientException {
        // Members
        public ErrorKind @kind;
        public string @code;
        public string @msg;
        public string? @details;

        // Constructor
        public MatrixApi(
                ErrorKind @kind, 
                string @code, 
                string @msg, 
                string? @details) : base(
                "@kind" + "=" + @kind+ ", " +
                "@code" + "=" + @code+ ", " +
                "@msg" + "=" + @msg+ ", " +
                "@details" + "=" + @details) {

            this.@kind = @kind;

            this.@code = @code;

            this.@msg = @msg;

            this.@details = @details;
        }
    }
    

    
}

class FfiConverterTypeClientError : FfiConverterRustBuffer<ClientException>, CallStatusErrorHandler<ClientException> {
    public static FfiConverterTypeClientError INSTANCE = new FfiConverterTypeClientError();

    public override ClientException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new ClientException.Generic(
                    FfiConverterString.INSTANCE.Read(stream),
                    FfiConverterOptionalString.INSTANCE.Read(stream));
            case 2:
                return new ClientException.MatrixApi(
                    FfiConverterTypeErrorKind.INSTANCE.Read(stream),
                    FfiConverterString.INSTANCE.Read(stream),
                    FfiConverterString.INSTANCE.Read(stream),
                    FfiConverterOptionalString.INSTANCE.Read(stream));
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeClientError.Read()", value));
        }
    }

    public override int AllocationSize(ClientException value) {
        switch (value) {

            case ClientException.Generic variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg)
                    + FfiConverterOptionalString.INSTANCE.AllocationSize(variant_value.@details);

            case ClientException.MatrixApi variant_value:
                return 4
                    + FfiConverterTypeErrorKind.INSTANCE.AllocationSize(variant_value.@kind)
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@code)
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg)
                    + FfiConverterOptionalString.INSTANCE.AllocationSize(variant_value.@details);
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeClientError.AllocationSize()", value));
        }
    }

    public override void Write(ClientException value, BigEndianStream stream) {
        switch (value) {
            case ClientException.Generic variant_value:
                stream.WriteInt(1);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                FfiConverterOptionalString.INSTANCE.Write(variant_value.@details, stream);
                break;
            case ClientException.MatrixApi variant_value:
                stream.WriteInt(2);
                FfiConverterTypeErrorKind.INSTANCE.Write(variant_value.@kind, stream);
                FfiConverterString.INSTANCE.Write(variant_value.@code, stream);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                FfiConverterOptionalString.INSTANCE.Write(variant_value.@details, stream);
                break;
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeClientError.Write()", value));
        }
    }
}





public enum ComparisonOperator: int {
    /// <summary>
    /// Equals
    /// </summary>
    Eq,
    /// <summary>
    /// Less than
    /// </summary>
    Lt,
    /// <summary>
    /// Greater than
    /// </summary>
    Gt,
    /// <summary>
    /// Greater or equal
    /// </summary>
    Ge,
    /// <summary>
    /// Less or equal
    /// </summary>
    Le
}

class FfiConverterTypeComparisonOperator: FfiConverterRustBuffer<ComparisonOperator> {
    public static FfiConverterTypeComparisonOperator INSTANCE = new FfiConverterTypeComparisonOperator();

    public override ComparisonOperator Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1: return ComparisonOperator.Eq;
            case 2: return ComparisonOperator.Lt;
            case 3: return ComparisonOperator.Gt;
            case 4: return ComparisonOperator.Ge;
            case 5: return ComparisonOperator.Le;
            default: throw new publicException(String.Format("invalid enum value '{0}' in FfiConverterTypeComparisonOperator.Read()", value));
        }
    }

    public override int AllocationSize(ComparisonOperator value) {
        return 4;
    }

    public override void Write(ComparisonOperator value, BigEndianStream stream) {
        switch (value) {
            case ComparisonOperator.Eq: stream.WriteInt(1); break;
            case ComparisonOperator.Lt: stream.WriteInt(2); break;
            case ComparisonOperator.Gt: stream.WriteInt(3); break;
            case ComparisonOperator.Ge: stream.WriteInt(4); break;
            case ComparisonOperator.Le: stream.WriteInt(5); break;
            default: throw new publicException(String.Format("invalid enum value '{0}' in FfiConverterTypeComparisonOperator.Write()", value));
        }
    }
}







