                FFIObjectUtil.DisposeAll(
                    variant_value.AudioInfo,
                    variant_value.Source);
                break;
            case DraftAttachment.File variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.FileInfo,
                    variant_value.Source);
                break;
            case DraftAttachment.Image variant_value:
