/// <summary>
/// Contains the 2 possible identifiers of an event, either it has a remote
/// event id or a local transaction id, never both or none.
/// </summary>
public record EventOrTransactionId {
    
    public record EventId (
        string EventIdValue
    ) : EventOrTransactionId {}
    
    public record TransactionId (
        string TransactionIdValue
    ) : EventOrTransactionId {}
    

    
}

class FfiConverterTypeEventOrTransactionId : FfiConverterRustBuffer<EventOrTransactionId>{
    public static FfiConverterRustBuffer<EventOrTransactionId> INSTANCE = new FfiConverterTypeEventOrTransactionId();

    public override EventOrTransactionId Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new EventOrTransactionId.EventId(
                    FfiConverterString.INSTANCE.Read(stream)
                );
            case 2:
                return new EventOrTransactionId.TransactionId(
                    FfiConverterString.INSTANCE.Read(stream)
                );
            default:
                throw new publicException(String.Format("invalid enum value '{0}' in FfiConverterTypeEventOrTransactionId.Read()", value));
        }
    }

    public override int AllocationSize(EventOrTransactionId value) {
        switch (value) {
            case EventOrTransactionId.EventId variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.EventIdValue);
            case EventOrTransactionId.TransactionId variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.TransactionIdValue);
            default:
                throw new publicException(String.Format("invalid enum value '{0}' in FfiConverterTypeEventOrTransactionId.AllocationSize()", value));
        }
    }

    public override void Write(EventOrTransactionId value, BigEndianStream stream) {
        switch (value) {
            case EventOrTransactionId.EventId variant_value:
                stream.WriteInt(1);
                FfiConverterString.INSTANCE.Write(variant_value.EventIdValue, stream);
                break;
            case EventOrTransactionId.TransactionId variant_value:
                stream.WriteInt(2);
                FfiConverterString.INSTANCE.Write(variant_value.TransactionIdValue, stream);
                break;
            default:
                throw new publicException(String.Format("invalid enum value '{0}' in FfiConverterTypeEventOrTransactionId.Write()", value));
        }
    }
}







