public class FocusEventException: UniffiException {
    FocusEventException() : base() {}
    FocusEventException(String @Message) : base(@Message) {}

    // Each variant is a nested class
    
    
    public class InvalidEventId : FocusEventException {
        // Members
        public string @eventId;
        public string @err;

        // Constructor
        public InvalidEventId(
                string @eventId, 
                string @err) : base(
                "@eventId" + "=" + @eventId+ ", " +
                "@err" + "=" + @err) {

            this.@eventId = @eventId;

            this.@err = @err;
        }
    }
    
    
    public class EventNotFound : FocusEventException {
        // Members
        public string @eventId;

        // Constructor
        public EventNotFound(
                string @eventId) : base(
                "@eventId" + "=" + @eventId) {

            this.@eventId = @eventId;
        }
    }
    
    
    public class Other : FocusEventException {
        // Members
        public string @msg;

        // Constructor
        public Other(
                string @msg) : base(
                "@msg" + "=" + @msg) {

            this.@msg = @msg;
        }
    }
    

    
}

class FfiConverterTypeFocusEventError : FfiConverterRustBuffer<FocusEventException>, CallStatusErrorHandler<FocusEventException> {
    public static FfiConverterTypeFocusEventError INSTANCE = new FfiConverterTypeFocusEventError();

    public override FocusEventException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new FocusEventException.InvalidEventId(
                    FfiConverterString.INSTANCE.Read(stream),
                    FfiConverterString.INSTANCE.Read(stream));
            case 2:
                return new FocusEventException.EventNotFound(
                    FfiConverterString.INSTANCE.Read(stream));
            case 3:
                return new FocusEventException.Other(
                    FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeFocusEventError.Read()", value));
        }
    }

    public override int AllocationSize(FocusEventException value) {
        switch (value) {

            case FocusEventException.InvalidEventId variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@eventId)
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@err);

            case FocusEventException.EventNotFound variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@eventId);

            case FocusEventException.Other variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeFocusEventError.AllocationSize()", value));
        }
    }

    public override void Write(FocusEventException value, BigEndianStream stream) {
        switch (value) {
            case FocusEventException.InvalidEventId variant_value:
                stream.WriteInt(1);
                FfiConverterString.INSTANCE.Write(variant_value.@eventId, stream);
                FfiConverterString.INSTANCE.Write(variant_value.@err, stream);
                break;
            case FocusEventException.EventNotFound variant_value:
                stream.WriteInt(2);
                FfiConverterString.INSTANCE.Write(variant_value.@eventId, stream);
                break;
            case FocusEventException.Other variant_value:
                stream.WriteInt(3);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeFocusEventError.Write()", value));
        }
    }
}





