/// <summary>
/// Enum describing the progress of logging in by generating a QR code and
/// having an existing device scan it.
/// </summary>
public record GeneratedQrLoginProgress: IDisposable  {
    
    /// <summary>
    /// The login process is starting.
    /// </summary>
    public record Starting: GeneratedQrLoginProgress {}
    
    
    /// <summary>
    /// We have established the secure channel and now need to display the
    /// QR code so that the existing device can scan it.
    /// </summary>
    public record QrReady (
        QrCodeData QrCode
    ) : GeneratedQrLoginProgress {}
    
    /// <summary>
    /// The existing device has scanned the QR code and is displaying the
    /// checkcode. We now need to ask the user to enter the checkcode so that
    /// we can verify that the channel is indeed secure.
    /// </summary>
    public record QrScanned (
        CheckCodeSender CheckCodeSender
    ) : GeneratedQrLoginProgress {}
    
    /// <summary>
    /// We are waiting for the login and for the OAuth 2.0 authorization server
    /// to give us an access token.
    /// </summary>
    public record WaitingForToken (
        string UserCode
    ) : GeneratedQrLoginProgress {}
    
    /// <summary>
    /// We are syncing secrets.
    /// </summary>
    public record SyncingSecrets: GeneratedQrLoginProgress {}
    
    
    /// <summary>
    /// The login has successfully finished.
    /// </summary>
    public record Done: GeneratedQrLoginProgress {}
    
    

    
    public void Dispose() {
        switch (this) {
            case GeneratedQrLoginProgress.Starting variant_value:
                break;
            case GeneratedQrLoginProgress.QrReady variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.QrCode);
                break;
            case GeneratedQrLoginProgress.QrScanned variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.CheckCodeSender);
                break;
            case GeneratedQrLoginProgress.WaitingForToken variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.UserCode);
                break;
            case GeneratedQrLoginProgress.SyncingSecrets variant_value:
                break;
            case GeneratedQrLoginProgress.Done variant_value:
                break;
            default:
                throw new publicException(String.Format("invalid enum value '{0}' in GeneratedQrLoginProgress.Dispose()", this));
        }
    }
    
}

class FfiConverterTypeGeneratedQrLoginProgress : FfiConverterRustBuffer<GeneratedQrLoginProgress>{
    public static FfiConverterRustBuffer<GeneratedQrLoginProgress> INSTANCE = new FfiConverterTypeGeneratedQrLoginProgress();

    public override GeneratedQrLoginProgress Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new GeneratedQrLoginProgress.Starting(
                );
            case 2:
                return new GeneratedQrLoginProgress.QrReady(
                    FfiConverterTypeQrCodeData.INSTANCE.Read(stream)
