/// <summary>
/// Enum describing the progress of granting login by generating a QR code to
/// be scanned on the new device.
/// </summary>
public record GrantGeneratedQrLoginProgress: IDisposable  {
    
    /// <summary>
    /// The login process is starting.
    /// </summary>
    public record Starting: GrantGeneratedQrLoginProgress {}
    
    
    /// <summary>
    /// We have established the secure channel and now need to display the
    /// QR code so that the existing device can scan it.
    /// </summary>
    public record QrReady (
        QrCodeData QrCode
    ) : GrantGeneratedQrLoginProgress {}
    
    /// <summary>
    /// The existing device has scanned the QR code and is displaying the
    /// checkcode. We now need to ask the user to enter the checkcode so that
    /// we can verify that the channel is indeed secure.
    /// </summary>
    public record QrScanned (
        CheckCodeSender CheckCodeSender
    ) : GrantGeneratedQrLoginProgress {}
    
    /// <summary>
    /// The secure channel has been confirmed using the [`CheckCode`] and this
    /// device is waiting for the authorization to complete.
    /// </summary>
    public record WaitingForAuth (
        string VerificationUri
    ) : GrantGeneratedQrLoginProgress {}
    
    /// <summary>
    /// We are syncing secrets.
    /// </summary>
    public record SyncingSecrets: GrantGeneratedQrLoginProgress {}
    
    
    /// <summary>
    /// The login has successfully finished.
    /// </summary>
    public record Done: GrantGeneratedQrLoginProgress {}
    
    

    
    public void Dispose() {
        switch (this) {
            case GrantGeneratedQrLoginProgress.Starting variant_value:
                break;
            case GrantGeneratedQrLoginProgress.QrReady variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.QrCode);
                break;
            case GrantGeneratedQrLoginProgress.QrScanned variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.CheckCodeSender);
                break;
            case GrantGeneratedQrLoginProgress.WaitingForAuth variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.VerificationUri);
                break;
            case GrantGeneratedQrLoginProgress.SyncingSecrets variant_value:
                break;
            case GrantGeneratedQrLoginProgress.Done variant_value:
                break;
            default:
                throw new publicException(String.Format("invalid enum value '{0}' in GrantGeneratedQrLoginProgress.Dispose()", this));
        }
    }
    
}

