public record HistoryVisibility {
    
    /// <summary>
    /// Previous events are accessible to newly joined members from the point
    /// they were invited onwards.
    ///
    /// Events stop being accessible when the member' state changes to
    /// something other than *invite* or *join*.
    /// </summary>
    public record Invited: HistoryVisibility {}
    
    
    /// <summary>
    /// Previous events are accessible to newly joined members from the point
    /// they joined the room onwards.
    /// Events stop being accessible when the member' state changes to
    /// something other than *join*.
    /// </summary>
    public record Joined: HistoryVisibility {}
    
    
    /// <summary>
    /// Previous events are always accessible to newly joined members.
    ///
    /// All events in the room are accessible, even those sent when the member
    /// was not a part of the room.
    /// </summary>
    public record Shared: HistoryVisibility {}
    
    
    /// <summary>
    /// All events while this is the `HistoryVisibility` value may be shared by
    /// any participating homeserver with anyone, regardless of whether they
    /// have ever joined the room.
    /// </summary>
    public record WorldReadable: HistoryVisibility {}
    
    
    /// <summary>
    /// A custom history visibility, up for interpretation by the consumer.
    /// </summary>
    public record Custom (
        string Repr
    ) : HistoryVisibility {}
    

    
}

