public class HumanQrGrantLoginException: UniffiException {
    HumanQrGrantLoginException(string message): base(message) {}

    // Each variant is a nested class
    // Flat enums carries a string error message, so no special implementation is necessary.
    
    /// <summary>
    /// The requested device ID is already in use.
    /// </summary>
    public class DeviceIdAlreadyInUse: HumanQrGrantLoginException {
        public DeviceIdAlreadyInUse(string message): base(message) {}
    }
    
    /// <summary>
    /// The check code was incorrect.
    /// </summary>
    public class InvalidCheckCode: HumanQrGrantLoginException {
        public InvalidCheckCode(string message): base(message) {}
    }
    
    /// <summary>
    /// The other client proposed an unsupported protocol.
    /// </summary>
    public class UnsupportedProtocol: HumanQrGrantLoginException {
        public UnsupportedProtocol(string message): base(message) {}
    }
    
    /// <summary>
    /// Secrets backup not set up properly.
    /// </summary>
    public class MissingSecretsBackup: HumanQrGrantLoginException {
        public MissingSecretsBackup(string message): base(message) {}
    }
    
    /// <summary>
    /// The rendezvous session was not found and might have expired.
    /// </summary>
    public class NotFound: HumanQrGrantLoginException {
        public NotFound(string message): base(message) {}
    }
    
    /// <summary>
    /// An unknown error has happened.
    /// </summary>
    public class Unknown: HumanQrGrantLoginException {
        public Unknown(string message): base(message) {}
    }
    
    /// <summary>
    /// The requested device was not returned by the homeserver.
    /// </summary>
    public class DeviceNotFound: HumanQrGrantLoginException {
        public DeviceNotFound(string message): base(message) {}
    }
    
    /// <summary>
    /// The other device is already signed in and so does not need to sign in.
    /// </summary>
    public class OtherDeviceAlreadySignedIn: HumanQrGrantLoginException {
        public OtherDeviceAlreadySignedIn(string message): base(message) {}
    }
    
    /// <summary>
    /// The sign in was cancelled.
    /// </summary>
    public class Cancelled: HumanQrGrantLoginException {
        public Cancelled(string message): base(message) {}
    }
    
    /// <summary>
    /// The sign in was not completed in the required time.
    /// </summary>
    public class Expired: HumanQrGrantLoginException {
        public Expired(string message): base(message) {}
    }
    
    /// <summary>
    /// A secure connection could not have been established between the two
    /// devices.
    /// </summary>
    public class ConnectionInsecure: HumanQrGrantLoginException {
        public ConnectionInsecure(string message): base(message) {}
    }
    
    /// <summary>
    /// The QR code specifies an unsupported protocol version.
    /// </summary>
    public class UnsupportedQrCodeType: HumanQrGrantLoginException {
        public UnsupportedQrCodeType(string message): base(message) {}
    }
    
}

