/// <summary>
/// Mimic the [`UiLatestEventValue`] type.
/// </summary>
public record LatestEventValue: IDisposable  {
    
    public record None: LatestEventValue {}
    
    
    public record Remote (
        Timestamp Timestamp,
        string Sender,
        bool IsOwn,
        ProfileDetails Profile,
        TimelineItemContent Content
    ) : LatestEventValue {}
    
    public record RemoteInvite (
        Timestamp Timestamp,
        string? Inviter,
        ProfileDetails InviterProfile
    ) : LatestEventValue {}
    
    public record Local (
        Timestamp Timestamp,
        string Sender,
        ProfileDetails Profile,
        TimelineItemContent Content,
        LatestEventValueLocalState State
    ) : LatestEventValue {}
    

    
    public void Dispose() {
        switch (this) {
            case LatestEventValue.None variant_value:
                break;
            case LatestEventValue.Remote variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.Timestamp,
                    variant_value.Sender,
                    variant_value.IsOwn,
                    variant_value.Profile,
                    variant_value.Content);
                break;
            case LatestEventValue.RemoteInvite variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.Timestamp,
                    variant_value.Inviter,
                    variant_value.InviterProfile);
                break;
            case LatestEventValue.Local variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.Timestamp,
                    variant_value.Sender,
                    variant_value.Profile,
                    variant_value.Content,
                    variant_value.State);
                break;
            default:
                throw new publicException(String.Format("invalid enum value '{0}' in LatestEventValue.Dispose()", this));
        }
    }
    
}

