public class LiveLocationException: UniffiException {
    LiveLocationException(string message): base(message) {}

    // Each variant is a nested class
    // Flat enums carries a string error message, so no special implementation is necessary.
    
    public class Network: LiveLocationException {
        public Network(string message): base(message) {}
    }
    
    public class NotFound: LiveLocationException {
        public NotFound(string message): base(message) {}
    }
    
    public class Redacted: LiveLocationException {
        public Redacted(string message): base(message) {}
    }
    
    public class Stripped: LiveLocationException {
        public Stripped(string message): base(message) {}
    }
    
    public class NotLive: LiveLocationException {
        public NotLive(string message): base(message) {}
    }
    
    public class Deserialization: LiveLocationException {
        public Deserialization(string message): base(message) {}
    }
    
    public class Other: LiveLocationException {
        public Other(string message): base(message) {}
    }
    
}

