                    variant_value.Content);
                break;
            case MessageType.Text variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.Content);
                break;
            case MessageType.Location variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.Content);
                break;
            case MessageType.Other variant_value:
