public record MsgLikeKind: IDisposable  {
    
    /// <summary>
    /// An `m.room.message` event or extensible event, including edits.
    /// </summary>
    public record Message (
        MessageContent Content
    ) : MsgLikeKind {}
    
    /// <summary>
    /// An `m.sticker` event.
    /// </summary>
    public record Sticker (
        string Body,
        ImageInfo Info,
        MediaSource Source
    ) : MsgLikeKind {}
    
    /// <summary>
    /// An `m.poll.start` event.
    /// </summary>
    public record Poll (
        string Question,
        PollKind Kind,
        ulong MaxSelections,
        PollAnswer[] Answers,
        Dictionary<string, string[]> Votes,
        Timestamp? EndTime,
        bool HasBeenEdited
    ) : MsgLikeKind {}
    
    /// <summary>
    /// A redacted message.
    /// </summary>
    public record Redacted: MsgLikeKind {}
    
    
    /// <summary>
    /// An `m.room.encrypted` event that could not be decrypted.
    /// </summary>
