public class NotificationSettingsException: UniffiException {
    NotificationSettingsException() : base() {}
    NotificationSettingsException(String @Message) : base(@Message) {}

    // Each variant is a nested class
    
    
    public class Generic : NotificationSettingsException {
        // Members
        public string @msg;

        // Constructor
        public Generic(
                string @msg) : base(
                "@msg" + "=" + @msg) {

            this.@msg = @msg;
        }
    }
    
    /// <summary>
    /// Invalid parameter.
    /// </summary>
    
    public class InvalidParameter : NotificationSettingsException {
        // Members
        public string @msg;

        // Constructor
        public InvalidParameter(
                string @msg) : base(
                "@msg" + "=" + @msg) {

            this.@msg = @msg;
        }
    }
    
    /// <summary>
    /// Invalid room id.
    /// </summary>
    
    public class InvalidRoomId : NotificationSettingsException {
        // Members
        public string @roomId;

        // Constructor
        public InvalidRoomId(
                string @roomId) : base(
                "@roomId" + "=" + @roomId) {

            this.@roomId = @roomId;
        }
    }
    
    /// <summary>
    /// Rule not found
    /// </summary>
    
    public class RuleNotFound : NotificationSettingsException {
        // Members
        public string @ruleId;

        // Constructor
        public RuleNotFound(
                string @ruleId) : base(
                "@ruleId" + "=" + @ruleId) {

            this.@ruleId = @ruleId;
        }
    }
    
    /// <summary>
    /// Unable to add push rule.
    /// </summary>
    public class UnableToAddPushRule : NotificationSettingsException {
        public UnableToAddPushRule() : base() {}
    }
    
    
    /// <summary>
    /// Unable to remove push rule.
    /// </summary>
    public class UnableToRemovePushRule : NotificationSettingsException {
        public UnableToRemovePushRule() : base() {}
    }
    
    
    /// <summary>
    /// Unable to save the push rules
    /// </summary>
    public class UnableToSavePushRules : NotificationSettingsException {
        public UnableToSavePushRules() : base() {}
    }
    
    
    /// <summary>
    /// Unable to update push rule.
    /// </summary>
    public class UnableToUpdatePushRule : NotificationSettingsException {
        public UnableToUpdatePushRule() : base() {}
    }
    
    

    
}

