public class OAuthException: UniffiException {
    OAuthException(string message): base(message) {}

    // Each variant is a nested class
    // Flat enums carries a string error message, so no special implementation is necessary.
    
    public class NotSupported: OAuthException {
        public NotSupported(string message): base(message) {}
    }
    
    public class MetadataInvalid: OAuthException {
        public MetadataInvalid(string message): base(message) {}
    }
    
    public class CallbackUrlInvalid: OAuthException {
        public CallbackUrlInvalid(string message): base(message) {}
    }
    
    public class Cancelled: OAuthException {
        public Cancelled(string message): base(message) {}
    }
    
    public class Generic: OAuthException {
        public Generic(string message): base(message) {}
    }
    
}

class FfiConverterTypeOAuthError : FfiConverterRustBuffer<OAuthException>, CallStatusErrorHandler<OAuthException> {
    public static FfiConverterTypeOAuthError INSTANCE = new FfiConverterTypeOAuthError();

    public override OAuthException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1: return new OAuthException.NotSupported(FfiConverterString.INSTANCE.Read(stream));
            case 2: return new OAuthException.MetadataInvalid(FfiConverterString.INSTANCE.Read(stream));
            case 3: return new OAuthException.CallbackUrlInvalid(FfiConverterString.INSTANCE.Read(stream));
            case 4: return new OAuthException.Cancelled(FfiConverterString.INSTANCE.Read(stream));
            case 5: return new OAuthException.Generic(FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeOAuthError.Read()", value));
        }
    }

    public override int AllocationSize(OAuthException value) {
        return 4 + FfiConverterString.INSTANCE.AllocationSize(value.Message);
    }

    public override void Write(OAuthException value, BigEndianStream stream) {
        switch (value) {
            case OAuthException.NotSupported:
                stream.WriteInt(1);
                break;
            case OAuthException.MetadataInvalid:
                stream.WriteInt(2);
                break;
            case OAuthException.CallbackUrlInvalid:
                stream.WriteInt(3);
                break;
            case OAuthException.Cancelled:
                stream.WriteInt(4);
                break;
            case OAuthException.Generic:
                stream.WriteInt(5);
                break;
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeOAuthError.Write()", value));
        }
    }
}





