public record PushCondition {
    
    /// <summary>
    /// A glob pattern match on a field of the event.
    /// </summary>
    public record EventMatch (
        string Key,
        string Pattern
    ) : PushCondition {}
    
    /// <summary>
    /// Matches unencrypted messages where `content.body` contains the owner's
    /// display name in that room.
    /// </summary>
    public record ContainsDisplayName: PushCondition {}
    
    
    /// <summary>
    /// Matches the current number of members in the room.
    /// </summary>
    public record RoomMemberCount (
        ComparisonOperator Prefix,
        ulong Count
    ) : PushCondition {}
    
    /// <summary>
    /// Takes into account the current power levels in the room, ensuring the
    /// sender of the event has high enough power to trigger the
    /// notification.
    /// </summary>
    public record SenderNotificationPermission (
        string Key
    ) : PushCondition {}
    
    /// <summary>
    /// Exact value match on a property of the event.
    /// </summary>
    public record EventPropertyIs (
        string Key,
        JsonValue Value
    ) : PushCondition {}
    
    /// <summary>
    /// Exact value match on a value in an array property of the event.
    /// </summary>
    public record EventPropertyContains (
        string Key,
        JsonValue Value
    ) : PushCondition {}
    

    
}

