    /// to give us an access token.
    /// </summary>
    public record WaitingForToken (
        string UserCode
    ) : QrLoginProgress {}
    
    /// <summary>
    /// We are syncing secrets.
    /// </summary>
    public record SyncingSecrets: QrLoginProgress {}
    
    
    /// <summary>
