public class RecoveryException: UniffiException {
    RecoveryException() : base() {}
    RecoveryException(String @Message) : base(@Message) {}

    // Each variant is a nested class
    
    /// <summary>
    /// A backup already exists on the homeserver, the recovery subsystem does
    /// not allow backups to be overwritten, disable recovery first.
    /// </summary>
    public class BackupExistsOnServer : RecoveryException {
        public BackupExistsOnServer() : base() {}
    }
    
    
    /// <summary>
    /// A typical SDK error.
    /// </summary>
    
    public class Client : RecoveryException {
        // Members
        public ClientException @source;

        // Constructor
        public Client(
                ClientException @source) : base(
                "@source" + "=" + @source) {

            this.@source = @source;
        }
    }
    
    /// <summary>
    /// Error in the secret storage subsystem, except for when importing a
    /// secret.
    /// </summary>
    
    public class SecretStorage : RecoveryException {
        // Members
        public string @errorMessage;

        // Constructor
        public SecretStorage(
                string @errorMessage) : base(
                "@errorMessage" + "=" + @errorMessage) {

            this.@errorMessage = @errorMessage;
        }
    }
    
    /// <summary>
    /// Error when importing a secret from secret storage.
    /// </summary>
    
    public class Import : RecoveryException {
        // Members
        public string @errorMessage;

        // Constructor
        public Import(
                string @errorMessage) : base(
                "@errorMessage" + "=" + @errorMessage) {

            this.@errorMessage = @errorMessage;
        }
    }
    

    
}

class FfiConverterTypeRecoveryError : FfiConverterRustBuffer<RecoveryException>, CallStatusErrorHandler<RecoveryException> {
    public static FfiConverterTypeRecoveryError INSTANCE = new FfiConverterTypeRecoveryError();

    public override RecoveryException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new RecoveryException.BackupExistsOnServer();
            case 2:
                return new RecoveryException.Client(
                    FfiConverterTypeClientError.INSTANCE.Read(stream));
            case 3:
                return new RecoveryException.SecretStorage(
                    FfiConverterString.INSTANCE.Read(stream));
            case 4:
                return new RecoveryException.Import(
                    FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeRecoveryError.Read()", value));
        }
    }

    public override int AllocationSize(RecoveryException value) {
        switch (value) {

            case RecoveryException.BackupExistsOnServer variant_value:
                return 4;

            case RecoveryException.Client variant_value:
                return 4
                    + FfiConverterTypeClientError.INSTANCE.AllocationSize(variant_value.@source);

            case RecoveryException.SecretStorage variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@errorMessage);

            case RecoveryException.Import variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@errorMessage);
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeRecoveryError.AllocationSize()", value));
        }
    }

    public override void Write(RecoveryException value, BigEndianStream stream) {
        switch (value) {
            case RecoveryException.BackupExistsOnServer variant_value:
                stream.WriteInt(1);
                break;
            case RecoveryException.Client variant_value:
                stream.WriteInt(2);
                FfiConverterTypeClientError.INSTANCE.Write(variant_value.@source, stream);
                break;
            case RecoveryException.SecretStorage variant_value:
                stream.WriteInt(3);
                FfiConverterString.INSTANCE.Write(variant_value.@errorMessage, stream);
                break;
            case RecoveryException.Import variant_value:
                stream.WriteInt(4);
                FfiConverterString.INSTANCE.Write(variant_value.@errorMessage, stream);
                break;
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeRecoveryError.Write()", value));
        }
    }
}





