public class RoomListException: UniffiException {
    RoomListException() : base() {}
    RoomListException(String @Message) : base(@Message) {}

    // Each variant is a nested class
    
    
    public class SlidingSync : RoomListException {
        // Members
        public string @error;

        // Constructor
        public SlidingSync(
                string @error) : base(
                "@error" + "=" + @error) {

            this.@error = @error;
        }
    }
    
    
    public class UnknownList : RoomListException {
        // Members
        public string @listName;

        // Constructor
        public UnknownList(
                string @listName) : base(
                "@listName" + "=" + @listName) {

            this.@listName = @listName;
        }
    }
    
    public class InputCannotBeApplied : RoomListException {
        public InputCannotBeApplied() : base() {}
    }
    
    
    
    public class RoomNotFound : RoomListException {
        // Members
        public string @roomName;

        // Constructor
        public RoomNotFound(
                string @roomName) : base(
                "@roomName" + "=" + @roomName) {

            this.@roomName = @roomName;
        }
    }
    
    
    public class InvalidRoomId : RoomListException {
        // Members
        public string @error;

        // Constructor
        public InvalidRoomId(
                string @error) : base(
                "@error" + "=" + @error) {

            this.@error = @error;
        }
    }
    
    
    public class EventCache : RoomListException {
        // Members
        public string @error;

        // Constructor
        public EventCache(
                string @error) : base(
                "@error" + "=" + @error) {

            this.@error = @error;
        }
    }
    
    
    public class IncorrectRoomMembership : RoomListException {
        // Members
        public Membership[] @expected;
        public Membership @actual;

        // Constructor
        public IncorrectRoomMembership(
                Membership[] @expected, 
                Membership @actual) : base(
                "@expected" + "=" + @expected+ ", " +
                "@actual" + "=" + @actual) {

            this.@expected = @expected;

            this.@actual = @actual;
        }
    }
    

    
}

