/// <summary>
/// An update to a room send queue.
/// </summary>
public record RoomSendQueueUpdate: IDisposable  {
    
    /// <summary>
    /// A new local event is being sent.
    /// </summary>
    public record NewLocalEvent (
        string TransactionId
    ) : RoomSendQueueUpdate {}
    
    /// <summary>
    /// A local event that hadn't been sent to the server yet has been cancelled
    /// before sending.
    /// </summary>
    public record CancelledLocalEvent (
        string TransactionId
    ) : RoomSendQueueUpdate {}
    
    /// <summary>
    /// A local event's content has been replaced with something else.
    /// </summary>
    public record ReplacedLocalEvent (
        string TransactionId
    ) : RoomSendQueueUpdate {}
    
    /// <summary>
    /// An error happened when an event was being sent.
    ///
    /// The event has not been removed from the queue. All the send queues
    /// will be disabled after this happens, and must be manually re-enabled.
    /// </summary>
    public record SendError (
        string TransactionId,
        QueueWedgeError Error,
        bool IsRecoverable
    ) : RoomSendQueueUpdate {}
    
    /// <summary>
    /// The event has been unwedged and sending is now being retried.
    /// </summary>
    public record RetryEvent (
        string TransactionId
    ) : RoomSendQueueUpdate {}
    
    /// <summary>
    /// The event has been sent to the server, and the query returned
    /// successfully.
    /// </summary>
    public record SentEvent (
        string TransactionId,
        string EventId
    ) : RoomSendQueueUpdate {}
    
    /// <summary>
    /// A media upload (consisting of a file and possibly a thumbnail) has made
    /// progress.
    /// </summary>
    public record MediaUpload (
        string RelatedTo,
        MediaSource? File,
        ulong Index,
        AbstractProgress Progress
    ) : RoomSendQueueUpdate {}
    

    
    public void Dispose() {
        switch (this) {
            case RoomSendQueueUpdate.NewLocalEvent variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.TransactionId);
                break;
            case RoomSendQueueUpdate.CancelledLocalEvent variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.TransactionId);
                break;
            case RoomSendQueueUpdate.ReplacedLocalEvent variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.TransactionId);
                break;
            case RoomSendQueueUpdate.SendError variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.TransactionId,
                    variant_value.Error,
                    variant_value.IsRecoverable);
                break;
            case RoomSendQueueUpdate.RetryEvent variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.TransactionId);
                break;
            case RoomSendQueueUpdate.SentEvent variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.TransactionId,
                    variant_value.EventId);
                break;
            case RoomSendQueueUpdate.MediaUpload variant_value:
                FFIObjectUtil.DisposeAll(
                    variant_value.RelatedTo,
                    variant_value.File,
                    variant_value.Index,
                    variant_value.Progress);
                break;
            default:
                throw new publicException(String.Format("invalid enum value '{0}' in RoomSendQueueUpdate.Dispose()", this));
        }
    }
    
}

