public class SearchException: UniffiException {
    SearchException() : base() {}
    SearchException(String @Message) : base(@Message) {}

    // Each variant is a nested class
    
    
    public class IndexException : SearchException {
        // Members
        public string @v1;

        // Constructor
        public IndexException(
                string @v1) : base(
                "@v1" + "=" + @v1) {

            this.@v1 = @v1;
        }
    }
    
    
    public class EventLoadException : SearchException {
        // Members
        public string @v1;

        // Constructor
        public EventLoadException(
                string @v1) : base(
                "@v1" + "=" + @v1) {

            this.@v1 = @v1;
        }
    }
    

    
}

class FfiConverterTypeSearchError : FfiConverterRustBuffer<SearchException>, CallStatusErrorHandler<SearchException> {
    public static FfiConverterTypeSearchError INSTANCE = new FfiConverterTypeSearchError();

    public override SearchException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new SearchException.IndexException(
                    FfiConverterString.INSTANCE.Read(stream));
            case 2:
                return new SearchException.EventLoadException(
                    FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeSearchError.Read()", value));
        }
    }

    public override int AllocationSize(SearchException value) {
        switch (value) {

            case SearchException.IndexException variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@v1);

            case SearchException.EventLoadException variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@v1);
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeSearchError.AllocationSize()", value));
        }
    }

    public override void Write(SearchException value, BigEndianStream stream) {
        switch (value) {
            case SearchException.IndexException variant_value:
                stream.WriteInt(1);
                FfiConverterString.INSTANCE.Write(variant_value.@v1, stream);
                break;
            case SearchException.EventLoadException variant_value:
                stream.WriteInt(2);
                FfiConverterString.INSTANCE.Write(variant_value.@v1, stream);
                break;
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeSearchError.Write()", value));
        }
    }
}





