public class SsoException: UniffiException {
    SsoException(string message): base(message) {}

    // Each variant is a nested class
    // Flat enums carries a string error message, so no special implementation is necessary.
    
    public class CallbackUrlInvalid: SsoException {
        public CallbackUrlInvalid(string message): base(message) {}
    }
    
    public class LoginWithTokenFailed: SsoException {
        public LoginWithTokenFailed(string message): base(message) {}
    }
    
    public class Generic: SsoException {
        public Generic(string message): base(message) {}
    }
    
}

class FfiConverterTypeSsoError : FfiConverterRustBuffer<SsoException>, CallStatusErrorHandler<SsoException> {
    public static FfiConverterTypeSsoError INSTANCE = new FfiConverterTypeSsoError();

    public override SsoException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1: return new SsoException.CallbackUrlInvalid(FfiConverterString.INSTANCE.Read(stream));
            case 2: return new SsoException.LoginWithTokenFailed(FfiConverterString.INSTANCE.Read(stream));
            case 3: return new SsoException.Generic(FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeSsoError.Read()", value));
        }
    }

    public override int AllocationSize(SsoException value) {
        return 4 + FfiConverterString.INSTANCE.AllocationSize(value.Message);
    }

    public override void Write(SsoException value, BigEndianStream stream) {
        switch (value) {
            case SsoException.CallbackUrlInvalid:
                stream.WriteInt(1);
                break;
            case SsoException.LoginWithTokenFailed:
                stream.WriteInt(2);
                break;
            case SsoException.Generic:
                stream.WriteInt(3);
                break;
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeSsoError.Write()", value));
        }
    }
}





