public class SteadyStateException: UniffiException {
    SteadyStateException(string message): base(message) {}

    // Each variant is a nested class
    // Flat enums carries a string error message, so no special implementation is necessary.
    
    public class BackupDisabled: SteadyStateException {
        public BackupDisabled(string message): base(message) {}
    }
    
    public class Connection: SteadyStateException {
        public Connection(string message): base(message) {}
    }
    
    public class Lagged: SteadyStateException {
        public Lagged(string message): base(message) {}
    }
    
}

