        ThreadListItem Value
    ) : ThreadListUpdate {}
    
    /// <summary>
    /// A new item was appended at the back.
    /// </summary>
    public record PushBack (
        ThreadListItem Value
    ) : ThreadListUpdate {}
    
    /// <summary>
    /// The first item was removed.
    /// </summary>
    public record PopFront: ThreadListUpdate {}
    
    
    /// <summary>
    /// The last item was removed.
    /// </summary>
    public record PopBack: ThreadListUpdate {}
    
    
    /// <summary>
    /// An item was inserted at the given position.
    /// </summary>
    public record Insert (
        uint Index,
        ThreadListItem Value
    ) : ThreadListUpdate {}
    
    /// <summary>
    /// The item at the given position was replaced.
    /// </summary>
    public record Set (
        uint Index,
        ThreadListItem Value
    ) : ThreadListUpdate {}
    
    /// <summary>
    /// The item at the given position was removed.
    /// </summary>
    public record Remove (
        uint Index
    ) : ThreadListUpdate {}
    
    /// <summary>
    /// The list was truncated to the given length.
    /// </summary>
    public record Truncate (
        uint Length
    ) : ThreadListUpdate {}
    
    /// <summary>
